const response = $input.first().json;
const rawText = response.choices[0].message.content;

const cleaned = rawText
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch(e) {
  data = {
    customer_name: "Parse Error",
    consumer_number: "0",
    billing_month: "Unknown",
    units_consumed: "0",
    sanctioned_load: "0",
    total_amount: "0",
    tariff_category: "Unknown"
  };
}

// Fix units and sanctioned load if merged
if (data.units_consumed && data.units_consumed.toString().includes('KW')) {
  const parts = data.units_consumed.toString().split(' ');
  data.units_consumed = parts[0];
  data.sanctioned_load = parts[1] + ' ' + (parts[2] || '');
}

// Fix sanctioned load if it contains units
if (data.sanctioned_load && data.sanctioned_load.toString().includes('137')) {
  data.sanctioned_load = '1 KW';
}

return [{ json: data }];

// Get data sent as JSON from HTML
const body = $input.first().json.body;

return [{
  json: {
    fileName: body.filename || 'bill.jpg',
    mimeType: body.file_type || 'image/jpeg',
    fileData: body.fileData,
    groqApiKey: body.groq_api_key
  }
}];

