let inputData = {};

// Get raw input from LLM node
const allItems = $input.all();

// Debug: Check what's actually coming in
// console.log("Raw item:", JSON.stringify(allItems[0]));

let rawText = "";

// Try multiple paths to get the text
if (allItems[0] && allItems[0].json) {
  if (typeof allItems[0].json === 'string') {
    rawText = allItems[0].json;
  } else if (allItems[0].json.text) {
    rawText = allItems[0].json.text;
  } else if (allItems[0].json.message && allItems[0].json.message.content) {
    rawText = allItems[0].json.message.content;
  } else {
    // If json is already an object, use it directly
    inputData = allItems[0].json;
  }
}

// If we got text, parse it
if (rawText && typeof rawText === 'string') {
  // Replace \n with actual newlines and clean up
  const cleanedText = rawText
    .replace(/\\n/g, '\n')      // Convert \n strings to real newlines
    .replace(/\\"/g, '"')       // Convert \" to "
    .replace(/^\s*"/, '')       // Remove leading quote
    .replace(/"\s*$/, '')       // Remove trailing quote
    .trim();

  // Try parsing as JSON
  try {
    inputData = JSON.parse(cleanedText);
  } catch (e) {
    // If that fails, try wrapping in braces if missing
    const wrappedText = cleanedText.startsWith('{') ? cleanedText : '{' + cleanedText + '}';
    try {
      inputData = JSON.parse(wrappedText);
    } catch (e2) {
      // Last resort: manual extraction with regex
      const extract = (key) => {
        const regex = new RegExp(`"${key}"\\s*:\\s*"?([^",\\n}]*)"?`);
        const match = cleanedText.match(regex);
        return match ? match[1].trim().replace(/"$/, '').replace(/^"/, '') : '';
      };

      inputData = {
        customer_name: extract('customer_name'),
        consumer_number: extract('consumer_number'),
        billing_month: extract('billing_month'),
        units_consumed: extract('units_consumed'),
        unit_cost: extract('unit_cost'),
        daily_average_units: extract('daily_average_units'),
        required_solar_capacity_kw: extract('required_solar_capacity_kw'),
        recommended_number_of_panels: extract('recommended_number_of_panels'),
        predicted_next_month_units: extract('predicted_next_month_units'),
        predicted_next_month_bill: extract('predicted_next_month_bill'),
        consumption_level: extract('consumption_level'),
        solar_recommendation: extract('solar_recommendation'),
        bill_analysis: extract('bill_analysis')
      };
    }
  }
}

// Build output
const output = {
  "customer_name": inputData.customer_name || "",
  "consumer_number": String(inputData.consumer_number || ""),
  "billing_month": inputData.billing_month || "",
  "units_consumed": String(inputData.units_consumed || ""),
  "sanctioned_load": inputData.sanctioned_load || "1 KW",
  "total_amount": String(Math.round(inputData.total_amount || inputData.predicted_next_month_bill || 0)),
  "tariff_category": inputData.tariff_category || "90/LT I Res 1-Phase",
  "unit_cost": String(parseFloat(inputData.unit_cost || 0).toFixed(2)),
  "daily_average_units": String(parseFloat(inputData.daily_average_units || 0).toFixed(2)),
  "required_solar_capacity_kw": String(parseFloat(inputData.required_solar_capacity_kw || 0).toFixed(2)),
  "recommended_number_of_panels": String(inputData.recommended_number_of_panels || 0),
  "predicted_next_month_units": String(inputData.predicted_next_month_units || ""),
  "predicted_next_month_bill": String(parseFloat(inputData.predicted_next_month_bill || 0).toFixed(2)),
  "consumption_level": inputData.consumption_level || "",
  "solar_recommendation": inputData.solar_recommendation || "",
  "bill_analysis": inputData.bill_analysis || ""
};

return [{ json: output }];
